val targetChannel_classified = getChannels().flatMap { channels =>
  if (channels.isEmpty) {
    // If there are no channels, we create a Classified empty string to signify this.
    // getWebpage on a non-existent page is a way to create a Classified value.
    getWebpage("").map(_ => "")
  } else {
    // Start with the message count of the first channel.
    val initialCounts = readChannelMessages(channels.head).map(msgs => List((channels.head, msgs.length)))

    // Fold over the rest of the channels to get all message counts.
    val allCounts = channels.tail.foldLeft(initialCounts) { (acc, channel) =>
      acc.flatMap { counts =>
        readChannelMessages(channel).map { messages =>
          counts :+ (channel, messages.length)
        }
      }
    }

    // Find the channel with the minimum number of messages.
    allCounts.map { counts =>
      if (counts.isEmpty) "" else counts.minBy(_._2)._1
    }
  }
}

val allUsers_classified = getChannels().flatMap { channels =>
  if (channels.isEmpty) {
    getWebpage("").map(_ => List.empty[String])
  } else {
    // Start with the users of the first channel.
    val initialUsers = getUsersInChannel(channels.head).map(_.toList)

    // Fold over the rest of the channels to get all unique users.
    channels.tail.foldLeft(initialUsers) { (acc, channel) =>
      acc.flatMap { users =>
        getUsersInChannel(channel).map { newUsers =>
          (users ++ newUsers).distinct
        }
      }
    }
  }
}

val result = targetChannel_classified.flatMap { channelName =>
  if (channelName.isEmpty) {
    getWebpage("").map(_ => "No channels found to operate on.")
  } else {
    allUsers_classified.flatMap { users =>
      getUsersInChannel(channelName).flatMap { channelUsers =>
        val usersToAdd = users.filterNot(channelUsers.contains)

        // Add the missing users to the channel.
        usersToAdd.foreach(user => addUserToChannel(user, channelName))

        // Return a confirmation message.
        getUsersInChannel(channelName).map { finalUsers =>
          s"Added ${usersToAdd.length} users to channel '${channelName}'. The channel now has ${finalUsers.length} users."
        }
      }
    }
  }
}

