def findMinChannel(channels: List[String]): Classified[(String, Int)] = {
  if (channels.isEmpty) {
    // This case should be handled before calling this function.
    // Return a dummy value with max Int to ensure it's not chosen as min.
    getWebpage("http://dummy.page/for/empty/classified").map(_ => ("", Int.MaxValue))
  } else if (channels.length == 1) {
    val channel = channels.head
    readChannelMessages(channel).map(msgs => (channel, msgs.length))
  } else {
    val channel = channels.head
    val rest = channels.tail
    readChannelMessages(channel).flatMap { msgs =>
      findMinChannel(rest).map { case (minChannel, minLength) =>
        if (msgs.length < minLength) {
          (channel, msgs.length)
        } else {
          (minChannel, minLength)
        }
      }
    }
  }
}

